                "path": f"dataset[{i}]"
            }
            print(json.dumps(error_response))
            sys.exit(1)

    steps = pipeline["steps"]
    if not isinstance(steps, list):
        error_response = {
            "status": "error",
            "error_code": "SCHEMA_VALIDATION_FAILED",
            "message": "ETL_ERROR: pipeline.steps must be a list",
            "path": "pipeline.steps"
        }
