        print(json.dumps(success_response))
        sys.exit(0)
    else:
        # Return normalized (backward compatible with checkpoint 1)
        result = {
            "status": "ok",
            "normalized": {
                "steps": normalized_steps
            }
        }
        print(json.dumps(result))
        sys.exit(0)


if __name__ == "__main__":
    main()

